INSERT INTO curriculum_node (id, curriculum_id, parent_id, node_type, node_title, node_content, tenant_id, order_index, access_level, is_active, is_deleted, created_at) VALUES (8002033, 8002, NULL, 'markdown_book', 'Rule 33 — 意見には必ず根拠を添える：数値、事例、引用', '# Rule 33 — 意見には必ず根拠を添える：数値、事例、引用
> **要点.** 根拠のない意見は**感想**。根拠のある意見は**分析**。業務メールでは感想には意思決定の価値がない。提示するすべての意見には、**3種類のうち少なくとも1つの根拠**を添える：数値、具体例、出典引用。
>
> キーワード：**「意見＋1つの根拠」**。

## 悪い例
> 「安全セキュリティ社のほうが保全技術社より良いと思います。」

→ フオンは何を根拠にしているか分からない。感想の可能性。

## 良い例
> 「安全セキュリティ社を保全技術社より推奨いたします。根拠3点：
> - **数値：** 安全セキュリティ48万円、保全技術52万円（8%差）。
> - **事例：** 安全セキュリティ社は田貴株式会社（類似案件）で実績あり、証明書を添付。
> - **引用：** 当社トゥアンリーダーが両社の実績書類を精査、CISSP保有者2名体制の安全セキュリティ社を支持。」

→ フオンは*データ*をもって判断できる。

## 3種類の根拠
### 数値（定量データ）
- 価格、費用、売上
- 割合、比率、変動
- 時間、回数、頻度

### 具体例
- ケーススタディ
- 実際に起きた事象
- 画像、グラフ

### 出典引用
- 専門家の見解（氏名付き）
- 公式文書（リンク）
- 署名された報告書

## 根拠不要な意見
- 誰も意思決定の材料にしない個人的な好み。
- 「〜で嬉しく思います」— 感情であって分析ではない。

## 使えるフレーズ
> **「意見 ＋ 3種類のうち最低1つの根拠：数値、事例、出典。」**', 'system', 33, 'premium', TRUE, FALSE, NOW()) ON CONFLICT (id) DO UPDATE SET curriculum_id = EXCLUDED.curriculum_id, node_type = EXCLUDED.node_type, node_title = EXCLUDED.node_title, node_content = EXCLUDED.node_content, tenant_id = EXCLUDED.tenant_id, order_index = EXCLUDED.order_index, access_level = EXCLUDED.access_level, is_active = EXCLUDED.is_active, is_deleted = EXCLUDED.is_deleted, updated_at = NOW();
