INSERT INTO curriculum_node (id, curriculum_id, parent_id, node_type, node_title, node_content, tenant_id, order_index, access_level, is_active, is_deleted, created_at) VALUES (8002068, 8002, NULL, 'markdown_book', 'Rule 67 — 業務メール容量制限は10MB — 圧縮かリンク共有で', '# Rule 67 — 業務メール容量制限は10MB — 圧縮かリンク共有で
> **要点.** 多くの業務メールには**10MBまたは25MB**の容量制限がある。超過するとメールがブロックされるが、**エラー通知がすぐに届くとは限らない**。2〜3日後に送信失敗に気付く → 業務遅延。
